-- Phase 12 + 13: Locale column + Spanish templates + remaining 41 state templates
  -- Applied: 2026-04-26

  -- Step 1: Add locale column to lease_templates and lease_template_versions (idempotent)
  ALTER TABLE public.lease_templates ADD COLUMN IF NOT EXISTS locale TEXT NOT NULL DEFAULT 'en';
  ALTER TABLE public.lease_template_versions ADD COLUMN IF NOT EXISTS locale TEXT NOT NULL DEFAULT 'en';

  -- Step 2: Seed English templates for remaining 41 states + DC
  
  DO $$
  DECLARE v_template_id UUID;
  BEGIN
    INSERT INTO public.lease_templates (name, state_code, is_active, legal_review_status, template_body, locale, notes, created_by)
    VALUES ('Phase 13 — Alaska Standard Residential Lease', 'AK', TRUE, 'statute_derived',
      'ALASKA RESIDENTIAL LEASE AGREEMENT

  {% include "common/disclaimer" %}

  This Residential Lease Agreement ("Agreement") is entered into as of the date signed below, between:

  LANDLORD: {{landlord_name}}
  LANDLORD ADDRESS: {{landlord_address}}

  TENANT: {{tenant_full_name}}
  EMAIL: {{tenant_email}}
  PHONE: {{tenant_phone}}
  APPLICATION ID: {{app_id}}

  ----------------------------------------------------------

  1. PREMISES

  Landlord agrees to rent to Tenant the property located at:

  {{property_address}}

  (the "Premises"), to be used solely as a private residential dwelling in the State of Alaska.

  ----------------------------------------------------------

  2. LEASE TERM

  The lease term shall begin on {{lease_start_date}} and end on {{lease_end_date}}. This is a fixed-term tenancy.

  ----------------------------------------------------------

  3. RENT

  Tenant agrees to pay a monthly rent of {{monthly_rent}}, due on or before the 1st day of each calendar month, payable to Landlord at the address above or by any electronic method Landlord designates in writing.

  ----------------------------------------------------------

  4. LATE FEES

  Alaska law provides a 5-day grace period before a late fee may be charged . A late fee of {{late_fee_flat}}, plus {{late_fee_daily}} per day for each additional day rent remains unpaid, shall apply after expiration of the grace period.

  ----------------------------------------------------------

  5. SECURITY DEPOSIT

  Tenant shall pay a security deposit of {{security_deposit}} prior to taking possession. Maximum allowed: 2.00× monthly rent (https://www.akleg.gov/basis/statutes.asp#34). Interest on deposit: No statutory interest requirement. The deposit shall be returned within 14 days after lease termination, less lawful deductions for unpaid rent, damages beyond ordinary wear and tear, and other permitted charges.

  ----------------------------------------------------------

  6. MOVE-IN COSTS

  {% include "common/move_in_breakdown" %}

  ----------------------------------------------------------

  7. UTILITIES AND SERVICES

  {% include "common/utility_matrix" %}

  ----------------------------------------------------------

  8. USE OF PREMISES

  Tenant shall use the Premises only as a private residential dwelling, in compliance with all applicable federal, state, and local laws, ordinances, and regulations.

  ----------------------------------------------------------

  9. PETS POLICY

  {{pets_policy}}

  ----------------------------------------------------------

  10. SMOKING POLICY

  {{smoking_policy}}

  ----------------------------------------------------------

  11. MAINTENANCE AND REPAIRS

  Tenant shall keep the Premises clean and in good condition. Tenant shall promptly notify Landlord of any damage or needed repairs. Landlord shall maintain the Premises in a habitable condition as required by Alaska law.

  ----------------------------------------------------------

  12. LANDLORD ENTRY

  Landlord shall provide at least 24 hours advance written notice before entering the Premises for non-emergency purposes (https://www.akleg.gov/basis/statutes.asp#34). In cases of emergency, Landlord may enter without prior notice.

  ----------------------------------------------------------

  13. LEASE TERMINATION AND NOTICE

  Either party must provide at least {{notice_period_days}} days written notice before terminating this tenancy at the end of the lease term. Rent increase notice: 30 days required .

  ----------------------------------------------------------

  14. EVICTION

  Nonpayment of rent: Landlord may issue a 7-day notice to pay or vacate (https://www.akleg.gov/basis/statutes.asp#34). Other breach: Landlord may issue a 10-day notice to cure or vacate.

  ----------------------------------------------------------

  15. SUBLETTING

  Tenant shall not sublet the Premises or assign this Agreement without prior written consent of Landlord.

  ----------------------------------------------------------

  16. ALTERATIONS

  Tenant shall not make any structural alterations or improvements to the Premises without prior written consent of Landlord.

  ----------------------------------------------------------

  17. ABANDONMENT

  If Tenant abandons the Premises, Landlord may re-enter and re-rent the property in accordance with Alaska law.

  ----------------------------------------------------------

  18. JOINT AND SEVERAL LIABILITY

  If there is more than one Tenant, each shall be jointly and severally liable for all obligations under this Agreement.

  ----------------------------------------------------------

  19. LEAD PAINT DISCLOSURE

  {% if year_built_pre_1978 %}
  Federal law requires disclosure of known lead-based paint hazards in properties built before 1978. See attached Lead Paint Disclosure Addendum.
  {% endif %}

  ----------------------------------------------------------

  20. ENTIRE AGREEMENT

  This Agreement, together with all attached addenda, constitutes the entire agreement between the parties. No oral representations shall modify this Agreement.

  ----------------------------------------------------------

  21. GOVERNING LAW

  This Agreement shall be governed by the laws of the State of Alaska.

