  Co-Applicant date signed: {{co_applicant_signed_date}}
  {% endif %}

  Landlord/Manager signature: {{landlord_signature}}
  Date countersigned: {{landlord_signed_date}}

  {% include "common/disclaimer" %}',
      'en', 'Phase 13 rollout — statute-derived, attorney_reviewed=false', 'agent:phase13')
    ON CONFLICT DO NOTHING
